---
import BaseLayout from '../../../layouts/BaseLayout.astro';
import { getCollection } from 'astro:content';

const isDev = import.meta.env.DEV;
const posts = await getCollection('blog', ({ data }) => isDev || !data.draft);
const tagCounts = posts.flatMap((p) => p.data.tags).reduce((acc, tag) => {
  acc[tag] = (acc[tag] || 0) + 1;
  return acc;
}, {} as Record<string, number>);
const tags = Object.entries(tagCounts).sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]));
---

<BaseLayout title="All Tags - AstroStatic" description="Browse all blog post tags.">
  <section class="mx-auto max-w-3xl px-4 py-16">
    <a href="/blog" class="text-sm text-blue-600 dark:text-blue-400 hover:underline rounded focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-600 dark:focus-visible:outline-blue-400">&larr; All posts</a>
    <h1 class="mt-4 text-4xl font-bold">All Tags</h1>
    <p class="mt-2 text-gray-500 dark:text-gray-400">{tags.length} tag{tags.length !== 1 ? 's' : ''}</p>
    <div class="mt-8 flex flex-wrap gap-3">
      {tags.map(([tag, count]) => (
        <a
          href={`/blog/tags/${tag}`}
          class="inline-flex items-center gap-1.5 rounded-full bg-gray-100 dark:bg-gray-800 px-4 py-1.5 text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-blue-100 dark:hover:bg-blue-900 hover:text-blue-700 dark:hover:text-blue-300 transition-colors focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-blue-500 focus-visible:rounded-full"
        >
          {tag}
          <span class="rounded-full bg-gray-200 dark:bg-gray-700 px-1.5 py-0.5 text-xs font-semibold text-gray-600 dark:text-gray-300">
            {count}
          </span>
        </a>
      ))}
    </div>
  </section>
</BaseLayout>

